const t={macroDesigner:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Simula G-code sin conexión — pega o escribe un programa y observa la trayectoria del cabezal, el recuadro delimitador, los totales de desplazamiento y extrusión, y una estimación de tiempo, sin tocar la impresora. Explora la biblioteca de macros integrada como referencia."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Ayuda"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"Acerca del Diseñador de Macros"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Cerrar"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Cómo usar"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Escribe o pega G-code en el editor (se carga un cuadrado de ejemplo para empezar)."}},{t:0,b:{t:2,i:[{t:3}],s:"Pulsa Simular — la trayectoria 2D y las estadísticas se actualizan."}},{t:0,b:{t:2,i:[{t:3}],s:"Las líneas sólidas son movimientos de extrusión; las líneas discontinuas tenues son desplazamientos."}},{t:0,b:{t:2,i:[{t:3}],s:"Explora la biblioteca de macros e Inserta una para partir de sus comandos."}}],topics:{simulator:{title:{t:0,b:{t:2,i:[{t:3}],s:"El simulador"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Ejecuta el programa en un cabezal virtual: movimientos G0/G1, G90/G91 (absoluto/relativo), M82/M83 (modo del extrusor), G92 (fijar posición) y G28 (referencia → origen). Informa de la trayectoria, el recuadro delimitador, el desplazamiento y la extrusión totales, una estimación aproximada de tiempo a partir de las velocidades de avance, y una línea de tiempo por comando. No se envía nada a la impresora."}}},motion:{title:{t:0,b:{t:2,i:[{t:3}],s:"Trayectoria y tiempo"}},body:{t:0,b:{t:2,i:[{t:3}],s:"La vista 2D es la trayectoria XY (Z está en los límites). La estimación de tiempo divide la longitud de cada movimiento entre su velocidad de avance — ignora la aceleración, así que es un límite inferior aproximado, no el tiempo de impresión exacto. Los comandos que el simulador no modela (p. ej. M-codes, macros de alto nivel) se enumeran como advertencias y se omiten."}}},macros:{title:{t:0,b:{t:2,i:[{t:3}],s:"Biblioteca de macros"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Un conjunto de referencia de macros comunes de Klipper con su nombre, qué hacen y las secciones de configuración que necesitan. «Insertar» coloca los comandos de alto nivel de una macro en el editor como punto de partida — ten en cuenta que se expanden aún más en la impresora (la expansión completa de Jinja/macros está por llegar)."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glosario"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{gcode:{term:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},def:{t:0,b:{t:2,i:[{t:3}],s:"El lenguaje de movimiento línea por línea que ejecuta la impresora (movimientos, temperaturas, ventilador, …)."}}},feedrate:{term:{t:0,b:{t:2,i:[{t:3}],s:"Velocidad de avance (F)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Velocidad de movimiento en mm/min — F1200 son 20 mm/s. Define la rapidez con la que se ejecuta cada movimiento."}}},macro:{term:{t:0,b:{t:2,i:[{t:3}],s:"Macro"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un comando con nombre y reutilizable (p. ej. QUAD_GANTRY_LEVEL) que se expande a una secuencia de G-code."}}}}},editor:{label:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},simulate:{t:0,b:{t:2,i:[{t:3}],s:"Simular"}},simulating:{t:0,b:{t:2,i:[{t:3}],s:"Simulando…"}},sample:{t:0,b:{t:2,i:[{t:3}],s:"Cargar ejemplo"}},clear:{t:0,b:{t:2,i:[{t:3}],s:"Borrar"}}},library:{label:{t:0,b:{t:2,i:[{t:3}],s:"Macros integradas"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"Explorar macros…"}},insert:{t:0,b:{t:2,i:[{t:3}],s:"Insertar en el editor"}},requires:{t:0,b:{t:2,i:[{t:3,v:"Necesita: "},{t:4,k:"sections"}]}},none:{t:0,b:{t:2,i:[{t:3}],s:"—"}}},result:{title:{t:0,b:{t:2,i:[{t:3}],s:"Simulación"}},moves:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" movimientos"}]}},distance:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm de desplazamiento"}]}},extrude:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm extruidos"}]}},time:{t:0,b:{t:2,i:[{t:3,v:"~"},{t:4,k:"s"},{t:3,v:" s"}]}},bounds:{t:0,b:{t:2,i:[{t:3}],s:"Límites"}},empty:{t:0,b:{t:2,i:[{t:3}],s:"No hay movimientos que simular."}}},path:{title:{t:0,b:{t:2,i:[{t:3}],s:"Trayectoria del cabezal (XY)"}},noPath:{t:0,b:{t:2,i:[{t:3}],s:"Ejecuta una simulación para ver la trayectoria."}}},timeline:{title:{t:0,b:{t:2,i:[{t:3}],s:"Línea de tiempo"}},line:{t:0,b:{t:2,i:[{t:3}],s:"Línea"}},cmd:{t:0,b:{t:2,i:[{t:3}],s:"Comando"}},action:{t:0,b:{t:2,i:[{t:3}],s:"Acción"}}},warnings:{title:{t:0,b:{t:2,i:[{t:3}],s:"Advertencias"}}},explain:{title:{t:0,b:{t:2,i:[{t:3}],s:"Explicar esta macro"}},travel:{t:0,b:{t:2,i:[{t:3,v:"Desplazamiento rápido a X"},{t:4,k:"x"},{t:3,v:" Y"},{t:4,k:"y"},{t:3,v:" a "},{t:4,k:"f"},{t:3,v:" mm/min"}]}},print:{t:0,b:{t:2,i:[{t:3,v:"Movimiento de impresión — extruir "},{t:4,k:"e"},{t:3,v:" mm en "},{t:4,k:"d"},{t:3,v:" mm hasta X"},{t:4,k:"x"},{t:3,v:" Y"},{t:4,k:"y"},{t:3,v:" a "},{t:4,k:"f"},{t:3,v:" mm/min"}]}},retract:{t:0,b:{t:2,i:[{t:3,v:"Retraer "},{t:4,k:"e"},{t:3,v:" mm"}]}},prime:{t:0,b:{t:2,i:[{t:3,v:"Extruir "},{t:4,k:"e"},{t:3,v:" mm en el sitio"}]}},noMove:{t:0,b:{t:2,i:[{t:3}],s:"Sin movimiento"}},absXYZ:{t:0,b:{t:2,i:[{t:3}],s:"Cambiar a posicionamiento absoluto (G90)"}},relXYZ:{t:0,b:{t:2,i:[{t:3}],s:"Cambiar a posicionamiento relativo (G91)"}},absE:{t:0,b:{t:2,i:[{t:3}],s:"Cambiar a extrusión absoluta (M82)"}},relE:{t:0,b:{t:2,i:[{t:3}],s:"Cambiar a extrusión relativa (M83)"}},setPos:{t:0,b:{t:2,i:[{t:3}],s:"Fijar la posición actual (G92)"}},home:{t:0,b:{t:2,i:[{t:3}],s:"Hacer home de los ejes (G28) → origen"}},abs:{t:0,b:{t:2,i:[{t:3}],s:"ABS"}},rel:{t:0,b:{t:2,i:[{t:3}],s:"REL"}},cum:{t:0,b:{t:2,i:[{t:3,v:"hasta ahora: "},{t:4,k:"d"},{t:3,v:" mm · "},{t:4,k:"e"},{t:3,v:" mm · ~"},{t:4,k:"s"},{t:3,v:" s"}]}},note:{t:0,b:{t:2,i:[{t:3}],s:"Las líneas con expresiones sin resolver o control Jinja no se simulan y se omiten aquí."}}},live:{label:{t:0,b:{t:2,i:[{t:3}],s:"Desde la impresora"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"Elige una de tus macros instaladas…"}},hint:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" macros encontradas en la impresora — elige una para cargar su G-code y simularla."}]}},unreachable:{t:0,b:{t:2,i:[{t:3}],s:"Impresora no accesible — conéctate para cargar tus macros instaladas."}},params:{t:0,b:{t:2,i:[{t:3}],s:"Parámetros de la macro"}}}}};export{t as default};
